import React, { useState } from "react";

// MUST match your backend domain
const apiBase = "https://prasa-app-yde3.onrender.com";

function Login({ onLoginSuccess }) {
  const [empld, setEmpld] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");

    if (!empld || !password) {
      setError("Please enter Employee ID and Password.");
      return;
    }

    try {
      setLoading(true);

      // FIX 1: Backend expects login_id, not empld
      const response = await fetch(`${apiBase}/login`, {
        method: "POST",
        headers: { 
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ login_id: empld, password }),
      });

      const data = await response.json();

      if (!response.ok || !data.success) {
        setError(data.message || "Invalid credentials");
      } else {
        onLoginSuccess(data.employee);
      }
    } catch (err) {
      console.error("Login Error:", err);
      setError("Server error. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        background: "linear-gradient(135deg, #0f9d58, #e8f5e9)",
        padding: 16,
      }}
    >
      <div
        style={{
          width: "100%",
          maxWidth: 380,
          backgroundColor: "#ffffff",
          borderRadius: 20,
          boxShadow: "0 10px 30px rgba(0,0,0,0.15)",
          padding: 24,
          textAlign: "center",
        }}
      >
        <img
          src="/logo.png"
          alt="PRASA Logo"
          style={{
            width: 90,
            height: 90,
            objectFit: "contain",
            backgroundColor: "#ffffff",
            borderRadius: 18,
            padding: 10,
            marginBottom: 10,
            boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
          }}
        />

        <h2 style={{ color: "#1b5e20", fontWeight: 700, marginBottom: 10 }}>
          PRASA Employee Login
        </h2>

        <form onSubmit={handleLogin} style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          <input
            type="text"
            placeholder="Enter EMPID"
            value={empld}
            onChange={(e) => setEmpld(e.target.value)}
            style={inputStyle}
          />

          <input
            type="password"
            placeholder="Enter Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            style={inputStyle}
          />

          <button
            type="submit"
            disabled={loading}
            style={buttonStyle}
          >
            {loading ? "Logging in..." : "Login"}
          </button>
        </form>

        {error && <p style={{ color: "red", marginTop: 10 }}>{error}</p>}
      </div>
    </div>
  );
}

const inputStyle = {
  padding: 10,
  borderRadius: 10,
  border: "1px solid #c8e6c9",
  fontSize: 14,
  outline: "none",
};

const buttonStyle = {
  marginTop: 14,
  backgroundColor: "#0f9d58",
  color: "#ffffff",
  border: "none",
  padding: 12,
  borderRadius: 12,
  cursor: "pointer",
  fontSize: 15,
  fontWeight: 600,
};

export default Login;
